theme.customCss:
.info-container {
   font-size: 14px;
}
 .text-fade-in {
 transition: opacity .4s ease-in .2s;
 margin-bottom: 20px; 
} 
.m-2 {
    margin: 8px;
    margin-bottom: 16px;
}

.my-2 {
    margin-top: 8px;
}

@media (max-width: 500px) {
  .info-container {
    max-width: 300px !important;
  }
}

.typebot-host-bubble {
  padding-right: 12px;
  max-width: 85%;
}

#checkIcon {
  stroke-dasharray: 40;
  stroke-dashoffset: 40;
  z-index: 99;
}

#checkIcon path:nth-child(1) {  
  animation: showIcon 250ms ease forwards;
  animation-delay: 500ms;
}

#checkIcon path:nth-child(2) {  
  animation: showIcon 250ms ease forwards;
  animation-delay: 400ms;
}

.hora {  
    position: absolute;
    bottom: 0px;
    right: 10px;
    font-size: 12px;
    z-index: 995;
    color: grey;
    animation-name: mostrar;
    animation-duration: 2s;
}

.hora2 {  
    position: absolute;
    bottom: 0px;
    right: 26px;
    font-size: 12px;
    z-index: 995;
    color: grey;
    animation-name: mostrar;
    animation-duration: 2s;
}

@keyframes showIcon {
    to { stroke-dashoffset: 0 };
}

@keyframes mostrar {
    from { opacity: 0; }
    to   { opacity: 1; }
}

/********** check style  **********/

.typebot-chat-view > .flex:first-child {
    padding-top: 30px;
}



.typebot-input .typebot-button {
    background: #008a7c;
    border-radius: 50%;
    color: #fff;
    position: relative;
    width: 50px;
    height: 50px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.typebot-container {
    background-size: initial!important;
    background-repeat: repeat-x!important;
}

.typebot-host-bubble>.bubble-typing {
  border-radius: 12px 12px 12px 0;
}

.typebot-host-bubble>.bubble-typing:after {
    position: absolute;
    content: "";
    width: 0;
    height: 0;
    border-style: solid;
    border-width: 0px 10px 10px 0;
    border-color: transparent #fff transparent transparent;
    bottom: 0;
    left: -9px;
    -moz-transform: scaleY(-1);
    -o-transform: scaleY(-1);
    -webkit-transform: scaleY(-1);
    transform: scaleY(-1);
}

.typebot-guest-bubble {
    position: relative;
    border-radius: 12px 12px 0 12px;
    padding-bottom: 19px;
    min-width: 70px;
}

.typebot-guest-bubble:after {
    position: absolute;
    content: "";
    width: 0;
    height: 0;
    border-style: solid;
    -moz-transform: scaleY(-1);
    -o-transform: scaleY(-1);
    -webkit-transform: scaleY(-1);
    transform: scaleY(-1);
}

.typebot-guest-bubble:after {
    border-width: 0px 0 10px 10px;
    border-color: transparent transparent transparent #e1ffc7;
    bottom: 0;
    right: -9px;
    border-style: solid;
}

iframe[src=""] {
  position: fixed;
  top: 0;
  left: 0;
  display: relative;
  width: 100%;
  height: 100% !important;
  z-index: 999999;
  border: none;
  padding: 0;
  margin: 0;
}


.hoje {
    position: fixed;
    z-index: 994;
    text-align: center;
    width: 50px;
    top: 60px;
    left: calc(50% - 25px);
    background-color: #ede8e2;
    margin: 0 auto;
    border-radius: 10px;
    font-size: 12px;
    font-weight: 800;
    box-shadow: 0px 1px #c6beb7;
    }
.lite-badge span {
    display: none;
}

.lite-badge svg {
